/* Vulkan layer interface v2 only needs vkNegotiateLoaderLayerInterfaceVersion
   exported by symbol name; the loader gets pointers to the GIPA and GDPA via
   the VkNegotiateLayerInterface struct filled in by that function.

   Exporting vkGetInstanceProcAddr or vkGetDeviceProcAddr from a layer .so
   can interfere with the loader's terminator/ICD path when it does
   dlsym(RTLD_DEFAULT, "vkGetInstanceProcAddr") and accidentally resolves
   to OUR symbol instead of the loader's, leading to recursive re-entry
   into vkCreateInstance while the loader-side mutex is held — classic
   deadlock observed on systems with multiple ICDs registered.

   Hide GIPA/GDPA. The loader will route through our negotiate-supplied
   function pointers instead.
*/
{
    global:
        vkNegotiateLoaderLayerInterfaceVersion;
    local:
        *;
};
